

var SMB2Forge = require('../tools/smb2-forge')
  , SMB2Request = SMB2Forge.request
  ;

/*
 * readdir
 * =======
 *
 * list the file / directory from the path provided:
 *
 *  - open the directory
 *
 *  - query directory content
 *
 *  - close the directory
 *
 */
module.exports = function(path, cb){
  var connection = this;

  // SMB2 open directory
  SMB2Request('open', {path:path}, connection, function(err, file){
    if(err) {
      var e = new Error('readdir OPEN failed: ' + err.message);
      e.code = err.code;
      return cb && cb(e);
    }
    // SMB2 query directory
    SMB2Request('query_directory', file, connection, function(err, files){
      if(err) {
        var e = new Error('readdir QUERY_DIR failed: ' + err.message);
        e.code = err.code;
        // try to close anyway
        SMB2Request('close', file, connection, function(){});
        return cb && cb(e);
      }
      // SMB2 close directory
      SMB2Request('close', file, connection, function(err){
        cb && cb(
          null
        , files.filter(function(v){ return v.Filename != '.' && v.Filename != '..' })
        );
      });
    });
  });
  
}


